sp_widget.client_script:
api.controller = function($scope, $timeout) {
    var c = this;
    c.showModal = false;
    c.showSuccessModal = false;
    c.status = "";
    c.failed = 0;
    c.migrationResult = {};
    c.batchSize = 100;
    c.showToast = false;
    c.migrating = false;
    c.progress = 0;
    c.current = 0;
    c.table_count = 0;
    c.total = 0;
    c.check = sessionStorage.getItem('currentId');
    c.logs = [];
    c.isCompleted = false;
    c.conn_name = sessionStorage.getItem('conn_name');

    /* ========================= NOTIFICATION SYSTEM ========================= */
    c.createNotification = function(notification) {
        $scope.server.get({
            action: "createNotification",
            payload: notification
        }).then(function() {
            $scope.$emit("notification.refresh");
        });
    };

    /* ========================= MIGRATION MODAL ========================= */
    c.openMigrationModal = function() {
        if (c.getTotalRecords() === 0) return;
        c.showModal = true;
        c.migrationResult = {};
        c.progress = 0;
        c.startMigration();
    };

    c.closeModal = function() {
        c.showModal = false;
    };

    c.closeSuccessModal = function() {
        c.showSuccessModal = false;
    };

    /* ========================= CART DATA ========================= */
    c.cart = [];

    /* ========================= LOAD CART ========================= */
    c.loadCart = function() {
        var raw = JSON.parse(sessionStorage.getItem("migration_cart") || "[]");
				//console.log('raw = ' + JSON.stringify(raw));
        c.selected_recs = raw.length;

        if (c.previousCartLength !== undefined && raw.length > c.previousCartLength) {
            var addedCount = raw.length - c.previousCartLength;
            c.createNotification({
                type: "queue_record_added",
                title: "Records added to migration queue",
                message: addedCount + " record(s) added to queue.",
                priority: "info"
            });
        }
        c.previousCartLength = raw.length;

        if (raw.length >= 10000) {
            c.createNotification({
                type: "queue_limit_reached",
                title: "Migration queue limit reached",
                message: "Maximum queue size reached (10,000 records).",
                priority: "warning"
            });
        }

        var grouped = {};
       raw.forEach(function(item) {
    // ✅ FIX: Normalize "Change Request" to "change_request" directly at processing time
    var tableName = (item.table || "")
        .toLowerCase()
        .replace(/\s+/g, '_')
        .replace(/[^a-z0-9_]/g, '');

    if (!grouped[tableName]) {
        grouped[tableName] = {
            name: tableName,
            label: item.label || item.table, // Keep the clean display name here
            records: []
        };
    } // ✅ FIX: normalize to lowercase
            if (!grouped[tableName]) {
                grouped[tableName] = {
                    name: tableName,
                    label: item.label || item.table,
                    records: []
                };
            }
            grouped[tableName].records.push({
                number: item.number || "",
                short_description: item.short_description || "",
                size: item.size || 0,
                table: tableName,
                sys_id: item.sys_id || "",
                state: item.state || "" // ✅ FIX: preserve state
            });
        });

        c.cart = Object.keys(grouped).map(function(key) {
            return grouped[key];
        });
				//console.log('cart = ' + JSON.stringify(c.cart));
        window.dispatchEvent(new Event("cartUpdated"));
        $scope.$emit("cartUpdated");
    };

    /* ========================= START MIGRATION ========================= */
    c.startMigration = function() {
        if (c.getTotalRecords() === 0) return;

        c.logs.push("Starting migration...");
        c.showModal = true;
        c.migrating = true;
        c.progress = 0;
        c.migrationResult = {};

        // ✅ FIX: cartRaw is a flat array, count directly
        var cartRaw = JSON.parse(sessionStorage.getItem('migration_cart') || '[]');
        c.total = cartRaw.length;

        var progressInterval;
        progressInterval = setInterval(function() {
            if (c.progress < 90) {
                c.progress += Math.floor(Math.random() * 5) + 1;
            }
            if (c.progress > 90) {
                c.progress = 90;
            }
            $scope.$applyAsync();
        }, 500);

        $scope.server.get({
            action: "migrateRecords",
            active_conn: sessionStorage.getItem('currentId'),
            cart_length: c.total,
            records: c.cart
        }).then(function(response) {
            clearInterval(progressInterval);
            c.progress = 100;
            c.migrating = false;

            if (response.data.success) {
                //var migration_logs = response.data.result.logs;
                //for (var log = 0; log < migration_logs.length; log++) {
                  //  c.logs.push(migration_logs[log]);
                //}
                c.logs.push("Migration started at " + response.data.sTime);
                c.logs.push("Migration completed at " + response.data.eTime);
                c.isCompleted = true;

                //var failed = (response.data.result &&
                  //            response.data.result.stats &&
                    //          response.data.result.stats.failed) || 0;
                //c.failed = failed;
                c.status = "success";

                c.showModal = false;
                c.showSuccessModal = true;
                c.duration = response.data.duration || "2m 34s";
                c.inserted = response.data.inserted || 0;
                c.updated = response.data.updated || 0;
                c.total = response.data.total || 0;
                c.url = response.data.url || 0;
                c.migrationResult = response.data.result;
                c.clearCart();

            } else {
                c.migrating = false;
                c.isCompleted = true;
                c.status = "failed";
                //c.failed = c.total;
                c.showModal = false;
                c.showSuccessModal = false;
                c.migrationResult = {
                    error: true,
                    message: response.data.message || "Migration failed"
                };
            }

        }, function(err) {
            clearInterval(progressInterval);
            c.migrating = false;
            c.isCompleted = true;
            c.progress = 0;
            c.status = "failed";
            c.failed = c.total || 0;
            c.showModal = false;
            c.showSuccessModal = true;
            c.migrationResult = {
                error: true,
                message: "Migration failed"
            };
            console.error(err);
        });
    };

    /* ========================= REMOVE RECORD ========================= */
    c.removeRecord = function(tableIndex, recordIndex) {
        var rec = c.cart[tableIndex].records[recordIndex];
        var recordLabel = rec.number || rec.sys_id || "Record";

        c.createNotification({
            type: "queue_record_removed",
            title: "Record removed from migration queue",
            message: recordLabel + " removed from queue.",
            priority: "info"
        });

        c.cart[tableIndex].records.splice(recordIndex, 1);
        if (c.cart[tableIndex].records.length === 0) {
            c.cart.splice(tableIndex, 1);
        }

        var raw = JSON.parse(sessionStorage.getItem("migration_cart") || "[]");
        raw = raw.filter(function(r) {
            return r.sys_id !== rec.sys_id;
        });
        sessionStorage.setItem("migration_cart", JSON.stringify(raw));
        sessionStorage.setItem('cart_items', JSON.stringify(raw));

        window.dispatchEvent(new Event("cartUpdated"));
        $scope.$emit("cartUpdated");
    };

    /* ========================= CLEAR CART ========================= */
    c.clearCart = function() {
        c.cart = [];
        sessionStorage.removeItem("migration_cart");
        window.dispatchEvent(new Event("cartUpdated"));
        $scope.$emit("cartUpdated");
        c.createNotification({
            type: "queue_cleared",
            title: "Migration queue cleared",
            message: "All records removed from migration queue.",
            priority: "warning"
        });
    };

    /* ========================= PREVIEW MODAL ========================= */
    c.previewOpen = false;
    c.previewData = {};

    c.openPreview = function(record) {
        c.previewData = record;
        c.previewOpen = true;
    };

    c.closePreview = function() {
        c.previewOpen = false;
    };

    /* ========================= TOTALS ========================= */
    c.getTotalRecords = function() {
        var total = 0;
        c.cart.forEach(function(table) {
            total += table.records.length;
        });
        return total;
    };

    c.getTotalTables = function() {
        return c.cart.length;
    };

    c.getTotalSize = function() {
        var total = 0;
        c.cart.forEach(function(table) {
            table.records.forEach(function(rec) {
                total += parseFloat(rec.size || 0);
            });
        });
        return total.toFixed(1);
    };

    c.getBatchCount = function() {
        var total = c.getTotalRecords();
        if (total === 0) return 0;
        return Math.ceil(total / c.batchSize);
    };

    /* ========================= INIT ========================= */
    c.loadCart();

    window.addEventListener("storage", function() {
        $scope.$apply(function() {
            c.loadCart();
        });
    });
};

sp_widget.css:
/* ===== Main Container ===== */
.migration-cart {
  display: flex;
  max-height: calc(100vh - 64px);
  position: relative;
  overflow-x: hidden;
  background: linear-gradient(
    to bottom right,
    #ffffff 0%,
    rgba(17, 106, 248, 0.05) 50%,
    rgba(10, 80, 245, 0.10) 100%
  );
}

.con {
  display: flex;
  min-height: 100vh;
  overflow-x: hidden;
}

.sidebar {
  flex-basis: 260px;
  flex-shrink: 0;
  height: 100%;
}

.cart-svg-icon s{
  color: #9BC0FC;
}

.main {
  position: relative;
  display: flex;
  flex-direction: column;
  gap: 30px;
  margin: 0 auto;
  overflow-y: auto;
  overflow-x: hidden;
  height: calc(100vh - 64px);
  width: 100%;
  min-width: 0;
  padding: 30px 15%;
  box-sizing: border-box;
}

/* ===== Header ===== */
.cart-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 25px;
}

.cart-header h2 {
  font-weight: 700;
  margin-bottom: 5px;
}

.subtitle {
  color: #64748b;
  font-size: 14px;
}

/* ===== Back Button ===== */
.back-link {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: #6b7280;
  text-decoration: none;
  font-size: 14px;
  margin-bottom: 10px;
  transition: all 0.2s ease;
}

.back-link:hover {
  color: #116AF8;
}

/* ===== Buttons ===== */
.btn-danger {
  background: #fff0f0;
  border: 1px solid #ffc9c9;
  color: #dc2626;
  border-radius: 8px;
  padding: 6px 14px;
  transition: transform 0.15s ease;
  box-shadow: none !important;
}

.btn-danger:hover {
  transform: scale(1.08);
  background: #fff0f0;
  box-shadow: none !important;
}

.btn-danger:focus,
.btn-danger:active,
.btn-danger:focus:active {
  box-shadow: none !important;
  outline: none !important;
  background: #fff0f0 !important;
  color: #dc2626 !important;
  transform: scale(1.05);
}

.btn {
  transition: none !important;
}

.btn-danger:active,
.btn-danger:focus {
  background: #fff0f0 !important;
  color: #dc2626 !important;
  box-shadow: none !important;
  outline: none;
}

.btn-primary {
  background: linear-gradient(to right, #116AF8, #0A50F5);
  box-shadow: 0 10px 20px rgba(17, 106, 248, 0.25);
  transition: all 0.3s ease;
  border: none;
  padding: 10px 20px;
  border-radius: 8px;
  color: white;
}

.btn-primary:hover {
  background: linear-gradient(to right, #0A50F5, #0842d0);
  box-shadow: 0 10px 25px rgba(10, 80, 245, 0.35);
}

/* ===== Stats ===== */
.stats-container {
  display: flex;
  gap: 20px;
  margin-bottom: 25px;
}

.stat-box {
  flex: 1;
  background: white;
  padding: 22px;
  border-radius: 14px;
  text-align: center;
  box-shadow: 0 8px 20px rgba(0,0,0,0.05);
}

.stat-box h3 {
  font-size: 26px;
  font-weight: 700;
  color: #116AF8;
}

/* ===== Cart Section ===== */
.cart-section {
  background: white;
  padding: 25px;
  border-radius: 14px;
  box-shadow: 0 8px 25px rgba(0,0,0,0.04);
  margin-bottom: 25px;
  width: 100%;
  box-sizing: border-box;
}

.cart-section.empty-mode {
  display: flex;
  justify-content: center;
  align-items: center;
  max-width: 100%;       /* ← was fixed 900px causing x-scroll */
  min-height: 420px;
  margin: 0 auto;
  border-radius: 18px;
}

.cart-section.has-records {
  display: block;
}

.cart-section h4 {
  margin-bottom: 20px;
  font-weight: 600;
}

.empty-cart-screen {
  width: 100%;
  max-width: 650px;
  text-align: center;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
}

.empty-icon {
  width: 90px;
  height: 90px;
  border-radius: 50%;
  background: #eef4ff;       /* ← light blue tint */
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 25px;
  font-size: 34px;
  color: #116AF8;            /* ← was #94a3b8 */
}

.empty-title {
  font-size: 34px;
  font-weight: 700;
  color: #0f172a;
  margin-bottom: 12px;
}

.empty-subtitle {
  font-size: 17px;
  color: #475569;
  line-height: 1.7;
  margin-bottom: 30px;
  max-width: 600px;
}

.browse-btn {
  background: #116AF8;
  color: white;
  padding: 14px 30px;
  border-radius: 10px;
  text-decoration: none;
  font-weight: 600;
  transition: all 0.3s ease;
}

.browse-btn:hover {
  background: linear-gradient(to right, #116AF8, #0A50F5);
  box-shadow: 0 10px 20px rgba(17, 106, 248, 0.3);
  color: white;
}

.browse-btn i {
  transition: transform 0.25s ease;
  display: inline-block;
}

.browse-btn:hover i {
  transform: translateX(4px);
}

/* ===== Table Card ===== */
.table-card {
  border-radius: 12px;
  margin-bottom: 20px;
  background: #f9fafc;
  border: 1px solid #e2e8f0;
}

.table-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 18px 22px;
  background: #f1f5f9;
  text-transform: uppercase;
  flex-wrap: nowrap;
}

.table-header,
.table-header * {
  white-space: nowrap !important;
}

.table-header .left {
  overflow: hidden;
  text-overflow: ellipsis;
}

.table-header small {
  font-weight: 700;
  font-size: 14px;
  color: #334155;
}

.badge-primary {
  background: #116AF8;
  padding: 8px 18px;
  border-radius: 999px;
  color: white;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 40px;
  line-height: 1;
}

/* ===== Record ===== */
.record-item {
  display: flex;
  justify-content: space-between;
  padding: 18px;
  border-top: 1px solid #e5e7eb;
}

.record-number {
  color: #116AF8;
  font-weight: 600;
}

.size-badge {
  background: #eef4ff;         /* ← was generic #eef2ff */
  color: #116AF8;              /* ← added for consistency */
  padding: 3px 10px;
  border-radius: 8px;
}

/* ===== Batch / Ready ===== */
.ready-section {
  background: linear-gradient(135deg, #dbeafe, #eff6ff);
  padding: 25px;
  border-radius: 14px;
  margin: 0 0 20px 0;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

/* ===== Toast ===== */
.migration-toast {
  position: fixed;
  bottom: 30px;
  right: 30px;
  background: #f1f5f9;
  border-radius: 12px;
  padding: 16px 20px;
}

/* ===== Loader ===== */
.migration-loader {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.5);
  display: flex;
  justify-content: center;
  align-items: center;
  flex-direction: column;
}

.spinner {
  width: 50px;
  height: 50px;
  border: 5px solid #9BC0FC;   /* ← was #ccc */
  border-top: 5px solid #116AF8;  /* ← was #4CAF50 */
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  100% { transform: rotate(360deg); }
}

/* ===== Modern Migration Modal ===== */
.migration-modal-backdrop {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;     /* vertical center */
  justify-content: center; /* horizontal center */
  background: rgba(0,0,0,0.55);
  z-index: 9999;

  /* 🔥 important fixes */
  padding: 20px;           /* prevents edge sticking on small screens */
  box-sizing: border-box;
} 	
.modern-migration-modal {
  width: 520px;
  padding: 40px 35px;
  border-radius: 18px;
  text-align: center;
  position: relative;

  background: linear-gradient(
    135deg,
    #0A50F5 0%,
    #116AF8 50%,
    #1e3a8a 100%
  );

  color: white;
  box-shadow: 0 25px 60px rgba(17,106,248,0.35);
  overflow: hidden;
}

/* subtle grid overlay */
.modern-migration-modal::before {
  content: "";
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(rgba(255,255,255,0.05) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,0.05) 1px, transparent 1px);
  background-size: 40px 40px;
  opacity: 0.3;
}

/* ===== Icon ===== */
  .modal-icon {
  width: 70px;
  height: 70px;
  margin: 0 auto 20px;
  border-radius: 16px;

  //background: linear-gradient(to right, #22d3ee, #06b6d4);
  display: flex;
  align-items: center;
  justify-content: center;

  font-size: 30px;
  transform: rotate(-10deg);
}
/* ===== ICON PULSE ANIMATION ===== */
@keyframes zoomPulse {
  0% {
    transform: scale(1) rotate(-10deg);
  }

  50% {
    transform: scale(1.15) rotate(-10deg);
  }

  100% {
    transform: scale(1) rotate(-10deg);
  }
}

.icon-animate {
  animation: zoomPulse 1.6s ease-in-out infinite;
}
/* ===== Title ===== */
.modern-migration-modal h2 {
  font-size: 26px;
  font-weight: 700;
  margin-bottom: 10px;
}

/* ===== Subtitle ===== */
.modal-subtitle {
  font-size: 14px;
  opacity: 0.9;
  margin-bottom: 30px;
}

/* ===== Stats ===== */
.modal-stats {
  display: flex;
  gap: 20px;
  margin-bottom: 25px;
}

.modal-stat-box {
  flex: 1;
  padding: 18px;
  border-radius: 14px;

  background: rgba(255,255,255,0.08);
  backdrop-filter: blur(10px);

  border: 1px solid rgba(255,255,255,0.15);
}

.modal-stat-box span {
  font-size: 12px;
  opacity: 0.85;
}

.modal-stat-box h3 {
  margin-top: 8px;
  font-size: 24px;
  font-weight: 700;
}

/* ===== Progress Bar ===== */
.modern-progress {
  width: 100%;
  height: 10px;
  background: rgba(255,255,255,0.2);
  border-radius: 999px;
  overflow: hidden;
  margin-bottom: 15px;
}

.modern-progress-fill {
  height: 100%;
  background: linear-gradient(
    to right,
    #22d3ee,
    #9BC0FC,
    #116AF8
  );
  transition: width 0.4s ease;
}

/* ===== Note ===== */
.modal-note {
  font-size: 12px;
  opacity: 0.85;
}
/* ===== Success Modal ===== */
.success-modal {
  width: 520px;
  padding: 35px;
  border-radius: 16px;
  text-align: center;
  position: relative;

  background: linear-gradient(135deg, #e6f4ea, #cfe9db);
  box-shadow: 0 25px 60px rgba(0,0,0,0.15);
}

/* Close */
.success-close {
  position: absolute;
  top: 15px;
  right: 18px;
  cursor: pointer;
  font-size: 20px;
  color: #64748b;
}

/* SUCCESS */
.success-bg {
  background: #16a34a;
}

/* FAILED */
.failed-bg {
  background: #dc2626;
}
/* ERROR TEXT */
.error-message {
  margin-top: 15px;
  font-size: 14px;
  color: #334155;
  line-height: 1.6;
  background: rgba(255,255,255,0.6);
  padding: 14px;
  border-radius: 10px;
  word-break: break-word;
}
/* icon base */
.success-icon {
  width: 80px;
  height: 80px;
  margin: 0 auto 20px;
  border-radius: 50%;
  color: white;
  font-size: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
}

/* Title */
.success-modal h2 {
  font-size: 24px;
  font-weight: 700;
  color: #0f172a;
}

/* Subtitle */
.success-sub {
  margin-top: 8px;
  font-size: 14px;
  color: #475569;
}

/* Stats */
.success-stats {
  display: flex;
  gap: 15px;
  margin: 25px 0;
}

.success-box {
  flex: 1;
  background: #ffffff;
  padding: 18px;
  border-radius: 12px;
  box-shadow: 0 8px 20px rgba(0,0,0,0.05);
}

.success-green {
  border: 2px solid #16a34a;
}

.success-box h3 {
  font-size: 22px;
  margin: 8px 0;
}

.success-box p {
  font-size: 12px;
  color: #64748b;
}

/* Buttons */
.success-actions {
  display: flex;
  justify-content: center;
  gap: 12px;
}

.btn-secondary {
  background: #f1f5f9;
  border: none;
  padding: 10px 18px;
  border-radius: 8px;
}

.btn-success {
  background: #16a34a;
  color: white;
  border: none;
  padding: 10px 18px;
  border-radius: 8px;
}
/* ===== Preview ===== */
.preview-overlay {
  position: fixed;
  inset: 0;
  background: rgba(15, 23, 42, 0.45);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 9999;
}

.preview-modal {
  background: white;
  width: 620px;
  border-radius: 18px;
  padding: 30px;
  box-shadow: 0 20px 45px rgba(17, 106, 248, 0.15);  /* ← blue tint */
  position: relative;
}

.preview-close {
  position: absolute;
  top: 18px;
  right: 20px;
  font-size: 24px;
  cursor: pointer;
  color: #64748b;
  font-weight: 400;
  transition: all 0.2s ease;
}

.preview-close:hover {
  color: #116AF8;              /* ← was #0f172a */
  transform: scale(1.1);
}

.preview-title {
  font-size: 24px;
  font-weight: 700;
  color: #116AF8;              /* ← was #1e293b */
  margin-bottom: 28px;
}

.preview-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 22px;
}

.preview-grid label {
  display: block;
  font-size: 13px;
  font-weight: 600;
  color: #116AF8;              /* ← was #64748b */
  margin-bottom: 6px;
}

.preview-grid div {
  font-size: 15px;
  color: #0f172a;
  line-height: 1.5;
}

.full-width {
  grid-column: 1 / span 2;
}

.preview-desc {
  background: #eef4ff;         /* ← was #f8fafc, now light blue */
  padding: 14px;
  border-radius: 10px;
  min-height: 60px;
}

.slider {
  background: #116AF8;
  color: #116AF8;
  accent-color: #116AF8;       /* ← ensures native slider thumb color */
}

.queue-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
}

.queue-header h4 {
  margin: 0;
  font-weight: 600;
}

.queue-start-btn {
  min-width: 160px;
}

.table-header-actions {
  display: flex;
  align-items: center;
  gap: 12px;
}

.table-start-btn {
  background: transparent;
  border: 1px solid #116AF8;
  color: #116AF8;
  padding: 8px 18px;
  border-radius: 999px;
  font-size: 13px;
  font-weight: 700;
  min-height: 40px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  transition: all 0.3s ease;
}

.table-start-btn:hover {
  background: linear-gradient(to right, #116AF8, #0A50F5);
  color: white;
  border-color: transparent;
  box-shadow: 0 10px 20px rgba(17, 106, 248, 0.25);
}

.table-start-btn svg {
  margin-right: 8px;
  display: inline-block;
  vertical-align: middle;
}

.actions {
  display: flex;
  align-items: center;
  gap: 12px;
}

.action-icon {
  cursor: pointer;
  color: #116AF8;              /* ← added */
  transition: color 0.2s
}

sp_widget.script:
(function() {
	data.side = $sp.getWidget('tracenow_sidebar');

	var duration = 0;
	var sTime = 0, eTime = 0;
	var stats = {
		inserted: 0,
		updated: 0,
		details: []
	};

	/* ========================= CREATE NOTIFICATION ========================= */
	if (input && input.action == "createNotification") {
		var notif = new GlideRecordSecure("x_sysus_tracenow_notifications");
		notif.initialize();
		notif.setValue("title", input.payload.title);
		notif.setValue("message", input.payload.message);
		notif.setValue("type", input.payload.type);
		notif.setValue("priority", input.payload.priority);
		notif.setValue("user", gs.getUserID());
		notif.setValue("read", false);
		notif.insert();
		data.notificationCreated = true;
		return;
	}

	/* ========================= MIGRATION EXECUTION ========================= */
	if (input && input.action == "migrateRecords") {
		var username, password, sourceurl;

		/* Migration Started Notification */
		var startNotif = new GlideRecordSecure("x_sysus_tracenow_notifications");
		startNotif.initialize();
		startNotif.title = "Migration started";
		startNotif.message = "Migration process has started.";
		startNotif.type = "migration_started";
		startNotif.priority = "info";
		startNotif.user = gs.getUserID();
		startNotif.insert();

		var gr = new GlideRecordSecure('x_sysus_tracenow_connection');
		gr.addQuery('sys_id', input.active_conn);
		gr.query();
		if (gr.next()) {
			username = gr.getValue('username');
			password = gr.getValue('password');
			sourceurl = gr.getValue('url');
			data.conn_name = gr.getValue('name');
		}

		var cart = input.records || [];
		var recordsToMigrate = [];

		(input.records || []).forEach(function(tableGroup) {
			console.log('tablegroup = ' + JSON.stringify(tableGroup));
			var table = tableGroup.name;


			(tableGroup.records || []).forEach(function(rec) {

				if (rec.sys_id) {

					recordsToMigrate.push({
							table: table,
							sysId: String(rec.sys_id).trim(),
							number: rec.number || '',
							state: rec.state || '',
							short_description: rec.short_description || ''
					});
				}

			});
		});
		console.log('recordstomigrate = ' + JSON.stringify(recordsToMigrate));

		/* ============= Check Stats of Tables =========== */
		var existingRecords = {};

		for (var i = 0; i < recordsToMigrate.length; i++) {
			var record = recordsToMigrate[i];

			// DEFENSIVE FIX: Convert "Change Request" -> "change_request" 
			// and strip any illegal label characters just in case.
			var cleanTableName = String(record.table)
			.toLowerCase()
			.replace(/\s+/g, '_')   // Replace spaces with underscores
			.replace(/[^a-z0-9_]/g, ''); // Remove special characters

			// Final sanity check to avoid throwing a fatal error if table name is completely invalid
			if (!gs.tableExists(cleanTableName)) {
				gs.warn("Tracelow Queue: Attempted to check stats on non-existent table: " + record.table + " (Cleaned: " + cleanTableName + ")");
				continue; 
			}

			var grCheck = new GlideRecordSecure(cleanTableName);
			existingRecords[
				record.table + ':' + record.sysId
			] = grCheck.get(record.sysId);
		}

		/* Run migration engine */
		try {
			console.log('cart_length = ' + input.cart_length);
			console.log('records = ' + JSON.stringify(input.records));
			console.log('recordsmigrate = ' + JSON.stringify(recordsToMigrate));
			var startTime = new Date().getTime(); // milliseconds
			var engine = new DM_MigrationCore();
			var result = engine.migrateMixedRecords(sourceurl, username, password, recordsToMigrate, { sortByTable: true, stopOnError: false });
			if(result) {
				data.success = true;
				data.result = result;
			}
			else data.success = false;
			var endTime = new Date().getTime();

			var durationMs = endTime - startTime;

			var totalSeconds = Math.floor(durationMs / 1000);
			var minutes = Math.floor(totalSeconds / 60);
			var seconds = totalSeconds % 60;

			var durationText = minutes + " min " + seconds + " sec";

			gs.info("Migration Duration: " + durationText);

			data.duration = durationText;
			//check the stats after migration
			var migrationDetails = [];
			for (var i = 0; i < recordsToMigrate.length; i++) {

				var record = recordsToMigrate[i];

				var key = record.table + ':' + record.sysId;

				var existedBefore = existingRecords[key];

				var grAfter = new GlideRecordSecure(record.table);

				var existsAfter = grAfter.get(record.sysId);

				if (!existsAfter) {

					stats.failed++;

					stats.details.push({
						table: record.table,
						sysId: record.sysId,
						action: 'failed'
					});

					migrationDetails.push({
            table: record.table,
            sys_id: record.sysId,
            number: record.number,
            state: record.state,
            short_description: record.short_description,
            status: "failed",
            action: "failed"
        });

					continue;
				}

				if (existedBefore) {

					stats.updated++;

					stats.details.push({
						table: record.table,
						sysId: record.sysId,
						action: 'updated'
					});

					migrationDetails.push({
            table: record.table,
            sys_id: record.sysId,
            number: record.number,
            state: record.state,
            short_description: record.short_description,
            status: "success",
            action: "updated"
        });

				} else {

					stats.inserted++;

					stats.details.push({
						table: record.table,
						sysId: record.sysId,
						action: 'inserted'
					});

					migrationDetails.push({
            table: record.table,
            sys_id: record.sysId,
            number: record.number,
            state: record.state,
            short_description: record.short_description,
            status: "success",
            action: "inserted"
        });

				}
			}
			//console.log('stats = ' + JSON.stringify(stats));
			/*var migration_result = JSON.stringify(result.results);
            console.log('migration_result = ' + migration_result);

            var inserted = (result.stats && result.stats.inserted) || 0;
            var updated  = (result.stats && result.stats.updated)  || 0;
            var failed   = (result.stats && result.stats.failed)   || 0;

            data.success  = true;
            data.result   = result;*/
            //sTime         = engine.startTime;
            //eTime         = engine.endTime;
            data.inserted = stats.inserted;
            data.updated  = stats.updated;
            data.total    = input.cart_length;
            data.url      = sourceurl;
            data.sTime    = sTime.toString();
            data.eTime    = eTime.toString();

            /* Success rate */

						var successRate = 0, partial = 0;
            if (data.total > 0) {
                successRate = ((stats.inserted + stats.updated) / input.cart_length) * 100;
            }
            successRate = Math.round(successRate * 100) / 100;

            /*for (var table in result.results) {
                var records = result.results[table];
                for (var sysId in records) {
                    var rec = records[sysId];
                    if (rec.success_rate == '75') {
                        successRate = '75';
                        data.inserted = 0;
                        data.updated = 0;
                        partial++;
                    }
                }
            }

            console.log('total = ' + data.total);

            /* Save migration record */
						var obj = {};
            var mig = new GlideRecordSecure('x_sysus_tracenow_migration_details');
            mig.initialize();

            var total = 0;
            cart.forEach(function(tableGroup) {
                total += (tableGroup.records || []).length;
            });

            mig.setValue('instance_url', sourceurl);
            mig.setValue('records_fetched', input.cart_length);
            mig.setValue('records_inserted', stats.inserted);
            mig.setValue('records_updated', stats.updated);
            mig.setValue('records_failed', 0);
            mig.setValue('partial_record', 0);
            mig.setValue('success_rate', successRate);
            mig.setValue('duration', durationText);
            mig.setValue('target_instance', gs.getProperty('glide.servlet.uri'));

            Object.keys(recordsToMigrate).forEach(function(key) {
                obj[key] = "true";
            });

            mig.setValue('table', JSON.stringify(migrationDetails));
            mig.insert();

            /* Result Notification */
			var resultNotif = new GlideRecordSecure("x_sysus_tracenow_notifications");
			resultNotif.initialize();

			if (engine.stats.failed == 0) {
				resultNotif.title   = "Migration completed successfully";
				resultNotif.message = (engine.stats.inserted + engine.stats.updated) + " records migrated successfully.";
				resultNotif.type    = "migration_success";
				resultNotif.priority = "success";
			} else if (engine.stats.failed > 0 && (engine.stats.inserted + engine.stats.updated) > 0) {
				resultNotif.title   = engine.stats.failed + " records failed during migration.";
				resultNotif.message = engine.stats.failed + " records failed during migration.";
				resultNotif.type    = "migration_warning";
				resultNotif.priority = "warning";
			} else {
				resultNotif.title   = "Migration failed";
				resultNotif.message = "Migration failed. No records migrated.";
				resultNotif.type    = "migration_failed";
				resultNotif.priority = "critical";
			}

			resultNotif.user = gs.getUserID();
			resultNotif.insert();

		} catch (e) {
			gs.error("Migration failed: " + e);
			console.log('error occurred ' + e);

			data.success = false;
			data.error   = e.toString();
			data.failed  = 0;

			var result_data = {};
			for (var i = 0; i < input.records.length; i++) {
				var group = input.records[i];
				var tableName = (group.name || "").toLowerCase(); // ✅ FIX: lowercase here too
				if (!result_data[tableName]) {
					result_data[tableName] = {};
				}
				for (var j = 0; j < group.records.length; j++) {
					var rc = group.records[j];
					data.failed++;
					result_data[tableName][rc.sys_id] = {
						status: "failed",
						rec_number: rc.number,
						success_rate: "0",
						reason: "The source table does not exist in the Target Instance"
					};
				}
			}

			var mig_gr = new GlideRecordSecure('x_sysus_tracenow_migration_details');
			mig_gr.initialize();
			mig_gr.setValue('instance_url', sourceurl);
			mig_gr.setValue('records_fetched', input.cart_length);
			mig_gr.setValue('records_inserted', 0);
			mig_gr.setValue('records_updated', 0);
			mig_gr.setValue('records_failed', data.failed);
			mig_gr.setValue('partial_record', 0);
			mig_gr.setValue('success_rate', 0);
			mig_gr.setValue('duration', '0 min 0 sec');
			mig_gr.setValue('target_instance', gs.getProperty('glide.servlet.uri'));
			mig_gr.setValue('table', JSON.stringify(result_data));
			mig_gr.insert();

			data.message = e.toString();

			var failNotif = new GlideRecordSecure("x_sysus_tracenow_notifications");
			failNotif.initialize();
			failNotif.title    = "Migration failed";
			failNotif.message  = e.toString();
			failNotif.type     = "migration_failed";
			failNotif.priority = "critical";
			failNotif.user     = gs.getUserID();
			failNotif.insert();
		}
	}

	/* ========================= PROGRESS ========================= */
	if (input && input.action == "getProgress") {
		var eng = new global.UnifiedMigrationEngine();
		var progress = eng.getProgress();
		data.progress = progress;
	}

})();
